# Memory Leaking in Rust with `Box::leak`

## The Function and Its Use Cases

```rust
use std::collections::HashMap;
use std::sync::OnceLock;

// ============================================================
// 1. BASIC DEMONSTRATION
// ============================================================

/// Leaks a value and returns a static reference to it.
/// The value lives for the entire program duration.
fn leak_to_static<T>(value: T) -> &'static T {
    Box::leak(Box::new(value))
}

// ============================================================
// 2. PRACTICAL USE CASE: Static configuration loaded at runtime
// ============================================================

#[derive(Debug)]
struct AppConfig {
    database_url: String,
    max_connections: u32,
    feature_flags: HashMap<String, bool>,
}

impl AppConfig {
    fn load_from_env() -> Self {
        AppConfig {
            database_url: std::env::var("DATABASE_URL")
                .unwrap_or_else(|_| "postgres://localhost/mydb".to_string()),
            max_connections: std::env::var("MAX_CONNECTIONS")
                .ok()
                .and_then(|v| v.parse().ok())
                .unwrap_or(10),
            feature_flags: HashMap::from([
                ("dark_mode".to_string(), true),
                ("beta_features".to_string(), false),
            ]),
        }
    }
}

/// Returns a static reference to configuration loaded once at startup.
/// 
/// WHY LEAK HERE:
/// - Config is needed everywhere, for the entire program lifetime
/// - Avoids Arc<> overhead on every access (no atomic ref counting)
/// - Config genuinely should never be freed before program exit
/// - Simplifies passing config through deeply nested call stacks
fn get_config() -> &'static AppConfig {
    static CONFIG: OnceLock<&'static AppConfig> = OnceLock::new();
    CONFIG.get_or_init(|| {
        Box::leak(Box::new(AppConfig::load_from_env()))
    })
}

